"""Вкладка «Текст»: сводка по серии + полный дамп последнего результата."""from __future__ import annotationsfrom PySide6.QtGui import QFontfrom PySide6.QtWidgets import QPlainTextEdit, QVBoxLayout, QWidgetfrom ...core.types import ExperimentResult, ExperimentSeriesclass TextOutputTab(QWidget):    def __init__(self, parent: QWidget | None = None) -> None:        super().__init__(parent)        self._text = QPlainTextEdit()        self._text.setReadOnly(True)        font = QFont("Monospace")        font.setStyleHint(QFont.TypeWriter)        self._text.setFont(font)        lay = QVBoxLayout(self)        lay.setContentsMargins(4, 4, 4, 4)        lay.addWidget(self._text)    # ---------- API ----------------------------------------------------------    def display_series(self, series: ExperimentSeries) -> None:        """Показать сводку по всей серии и последний результат."""        lines: list[str] = []        lines.append("=== СЕРИЯ ЭКСПЕРИМЕНТОВ ===")        lines.append(f"Время (UTC)  : {series.timestamp}")        lines.append(f"Сигнал       : {series.signal_name}")        lines.append(f"Шум          : {series.noise_name}")        lines.append(f"Фильтров     : {len(series.filter_names)} "                     f"({', '.join(series.filter_names)})")        lines.append(f"Испытаний    : {series.n_trials}")        lines.append(f"Режим seed   : {series.seed_mode}"                     f"{f' (base={series.base_seed})' if series.seed_mode=='manual' else ''}")        lines.append("")        lines.append("--- Агрегированные метрики (среднее ± std) ---")        for fname in series.filter_names:            a = series.aggregates[fname]            lines.append(f"  [{fname}]  n={a.n_trials}")            lines.append(f"    MSE         : {a.mse_mean:.4e} ± {a.mse_std:.2e}")            lines.append(f"    RMSE        : {a.rmse_mean:.4e} ± {a.rmse_std:.2e}")            lines.append(f"    SNR до, дБ  : {a.snr_before_db_mean:.3f} ± {a.snr_before_db_std:.3f}")            lines.append(f"    SNR после   : {a.snr_after_db_mean:.3f} ± {a.snr_after_db_std:.3f}")            lines.append(f"    ΔSNR, дБ    : {a.snr_improvement_db_mean:+.3f} ± {a.snr_improvement_db_std:.3f}")            lines.append(f"    Корреляция  : {a.correlation_mean:.4f} ± {a.correlation_std:.4f}")        last = series.last_result        if last is not None:            lines.append("")            lines.append("--- Последний результат ---")            lines.extend(self._format_result_block(last))        self._text.setPlainText("\n".join(lines))    def display_result(self, result: ExperimentResult) -> None:        """Совместимость: одиночный результат (старое поведение)."""        lines = ["=== ЭКСПЕРИМЕНТ ===", *self._format_result_block(result)]        self._text.setPlainText("\n".join(lines))    def clear(self) -> None:        self._text.clear()    # ---------- helpers ------------------------------------------------------    @staticmethod    def _format_result_block(result: ExperimentResult) -> list[str]:        m = result.metrics        lines: list[str] = []        lines.append(f"Время (UTC)    : {result.timestamp}")        lines.append(f"Сигнал         : {result.signal_name}")        lines.append(f"Шум            : {result.noise_name}")        lines.append(f"Фильтр         : {result.filter_name}")        lines.append(f"№ испытания    : {result.trial_index + 1}")        lines.append(f"Seed           : {result.seed}")        lines.append("")        lines.append("--- Параметры сигнала ---")        for k, v in result.clean.params.items():            lines.append(f"  {k} = {v}")        lines.append("")        lines.append("--- Параметры шума ---")        for k, v in result.noisy.params.items():            if k == "upstream":                continue            lines.append(f"  {k} = {v}")        lines.append("")        lines.append("--- Параметры фильтра ---")        for k, v in result.restored.params.items():            if k == "upstream":                continue            lines.append(f"  {k} = {v}")        lines.append("")        lines.append("=== МЕТРИКИ ===")        lines.append(f"  MSE              : {m.mse:.6e}")        lines.append(f"  RMSE             : {m.rmse:.6e}")        lines.append(f"  SNR до,  дБ      : {m.snr_before_db:.3f}")        lines.append(f"  SNR после, дБ    : {m.snr_after_db:.3f}")        lines.append(f"  Улучшение SNR, дБ: {m.snr_improvement_db:+.3f}")        lines.append(f"  Корреляция       : {m.correlation:.4f}")        return lines